<Stats id="monster-cockatrice_mythic--stats" atts={[6,17,11,2,13,8]} bab={6} cmb={3} cmd={17} feats={[["M","Dodge"],["Skill Focus"," (Perception)"],"Weapon Finesse"]} skills={{"fly":{"b":6},"per":{"b":11}}} />
