<Stats id="monster-gargoyle_mythic--stats" atts={[17,14,16,6,11,7]} bab={5} cmb={8} cmd={20} feats={["Improved Initiative",["M","Iron Will"],["Skill Focus"," (Fly)"]]} skills={{"fly":{"b":12},"per":{"b":5},"stl":{"b":11,"x":"+17 in stony environs"}}} racial="+2 Stealth (+8 in stony environs)" lang={["C","T"]} sq="freeze, opportunistic movement, possess statue" />
