<Stats id="monster-greater_barghest_mythic--stats" atts={[25,15,19,18,18,18]} bab={9} cmb={17} cmd={29} cmdP="33 vs. trip" feats={["Combat Casting","Combat Reflexes",["M","Great Fortitude"],"Improved Initiative","Lightning Reflexes"]} skills={{"acro":{"b":14,"x":"+18 when jumping"},"bluff":{"b":16},"climb":{"b":16}}} lang={["C","Gb","I"]} sq={<><Link to="/umr/change_shape">change shape</Link> (goblin or wolf; <Link to="/spell/polymorph">polymorph</Link>)</>} />
